mapper.select:
SELECT IFNULL(SUM(amount), 0)
FROM orders
WHERE status = 5
  AND order_time >= #{beginTime}
  AND order_time < #{endTime}

SELECT od.name, SUM(od.number) AS number FROM order_detail AS od JOIN orders o ON od.order_id = o.id WHERE o.`status` = 5
AND o.order_time > #{beginTime}
AND o.order_time < #{endTime}
GROUP BY od.`name` ORDER BY number DESC LIMIT 0,10
